// `npm-notice` header for the 404 NOT FOUND responses from the registry services
// (registry-frontdoor, npm-auth-ws) and cloudflare-registry when a valid auth token is required to access an endpoint.
const NpmNoticeMessageOn404 = 'Access token expired or revoked. Please try logging in again.'

// Error message to distinguish oidc config NOT FOUND cases from other 404 errors
const OidcNotFoundMessage = 'No valid oidc configs found for package'

module.exports = {
  OIDC,
  NpmNoticeMessageOn404,
  OidcNotFoundMessage,
}
